&lt;p&gt;&lt;span data-contrast=&quot;none&quot;&gt;쿠팡은&amp;nbsp;고객 감동 실현을 위해 존재합니다&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;.&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;고객들이&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&amp;nbsp;&quot;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;쿠팡&amp;nbsp;없이 그동안 어떻게 살았을까&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;?&quot;&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;라고 말할 때&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;,&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;비로소 우리의 미션을 실현하고 있음을 알 수 있습니다&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;.&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;고객들의 쇼핑과 식사&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;,&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;생활 전반을 편하게 만들겠다는 유일한 집념으로&amp;nbsp;쿠팡은&amp;nbsp;수억 달러 규모의&amp;nbsp;이커머스&amp;nbsp;산업 전반의 혁신을 이끌고 있습니다&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;.&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;쿠팡은&amp;nbsp;가장 빠르게 성장하는&amp;nbsp;이커머스&amp;nbsp;기업 중 하나로&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;,&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;국내 커머스 업계에서의 독보적인 입지와&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;,&amp;nbsp;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;고객 신뢰를 구축했습니다&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;.&lt;/span&gt; &lt;span data-ccp-props=&quot;{&amp;quot;201341983&amp;quot;:0,&amp;quot;335551550&amp;quot;:6,&amp;quot;335551620&amp;quot;:6,&amp;quot;335559739&amp;quot;:160,&amp;quot;335559740&amp;quot;:259}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
